CREATE PROC [dbo].[TR_THONGKE_SANPHAM_GETBYMONTH_EXPORT_HTML]
(
	@year int, 
	@month int
)
AS
BEGIN
	--DECLARE @year int, @month int;
	--SET @year = 2025;
	--SET @month = 1;

	DECLARE @currentDate date = DATEFROMPARTS(@year, @month, 1);
	DECLARE @prev_Date date = DATEADD(M, -6, @currentDate);
	DECLARE @firstDayOfMonth date = DATEFROMPARTS(YEAR(@prev_Date), MONTH(@prev_Date), 1);
	DECLARE @lastDayOfMonth date = EOMONTH(@currentDate);

	DECLARE @nextMonth DATE = @firstDayOfMonth;
	DECLARE @columns nvarchar(max) = '';
	WHILE @nextMonth <= @lastDayOfMonth
	BEGIN
		SET @columns = @columns + CONCAT('[',FORMAT(@nextMonth, 'MM-yyyy'), ']') + ','
		SET @nextMonth = DATEADD(MONTH, 1, @nextMonth);
	END
	IF LEN(@columns) > 0
	BEGIN
		SET @columns = SUBSTRING(@columns, 1, LEN(@columns) - 1)
	END

		---------
	SELECT NGAYNHAP, BOPHAN, PHANLOAI, SOLUONG
	INTO #TRANGTHAI_SANXUAT
	FROM (
		SELECT FORMAT(A.ngaythang, 'MM-yyyy') as NGAYNHAP,
				D.n_op AS BOPHAN, 
				METVUONG = SUM(CASE WHEN A.mact = '000' THEN B.m2_tc * A.soluong ELSE (A.rong*A.dai*A.soluong)/1000000 END),
				METKHOI = SUM(CASE WHEN A.mact = '000' THEN B.m3_tc * A.soluong ELSE A.sokhoi END)
		FROM tr_trangthai_sanxuat A 
			INNER JOIN tr_sanpham B ON A.masp1 = B.masp
			INNER JOIN trtb_m_location C ON A.congdoan = C.c_location
			INNER JOIN trtb_m_op D ON C.c_op = D.c_op
		WHERE D.department IN ('DONGGOI', 'SON')
			AND A.congdoan LIKE '%-PROD'
			AND A.ngaythang BETWEEN @firstDayOfMonth AND @lastDayOfMonth
		GROUP BY FORMAT(A.ngaythang, 'MM-yyyy'), D.n_op
	) AS TB
	UNPIVOT (
		SOLUONG FOR PHANLOAI IN (METVUONG, METKHOI)
	) AS unpvt;
------------------------------------------

	CREATE TABLE #THONGKE_SANPHAM
	(
		bophan nvarchar(200),
		phanloai nvarchar(50),
		col1 float,
		col2 float,
		col3 float,
		col4 float,
		col5 float,
		col6 float,
		col7 float
	)
	DECLARE @sql nvarchar(MAX) = '';
	
	SET @sql = N'
	INSERT INTO #THONGKE_SANPHAM
	SELECT * FROM #TRANGTHAI_SANXUAT
	PIVOT (
		SUM(SOLUONG)
		FOR NGAYNHAP IN (' + @columns + ')
	) PT '
	EXEC sp_executesql @sql;

	DECLARE @LastDay int = DATEDIFF(MONTH, @firstDayOfMonth, @lastDayOfMonth) + 1
	DECLARE @htmHeader nvarchar(max);
	DECLARE @tableWidth nvarchar(50) = CONCAT((@LastDay * 80) + 280, 'px');
	DECLARE @HtmlRow1 TABLE 
	(
		stt int IDENTITY(1,1),
		htmlString nvarchar(max)
	)

	INSERT @HtmlRow1(htmlString) VALUES (N'<h2 style=''TEXT-ALIGN: LEFT''>BẢNG TỔNG HỢP THEO THÁNG</h2>');
	INSERT @HtmlRow1(htmlString) VALUES (N'<table border=1 cellSpacing=0 cellPadding=2 style=''width: ' + @tableWidth + '''>');

	SET @htmHeader = N'<tr>'
	SET @htmHeader = @htmHeader + char(10) + N'<th>Bộ phận</th>';
	SET @htmHeader = @htmHeader + char(10) + N'<th>&nbsp;</th>'; -- PHAN LOAI
	
	SET @nextMonth = @firstDayOfMonth;
	WHILE @nextMonth <= @lastDayOfMonth
	BEGIN
		SET @htmHeader = @htmHeader + char(10) + N'<th>' + FORMAT(@nextMonth, 'MM-yyyy') + '</th>'
		SET @nextMonth = DATEADD(MONTH, 1, @nextMonth);
	END

	SET @htmHeader = @htmHeader + char(10) + N'</tr>'
	INSERT @HtmlRow1(htmlString) VALUES (@htmHeader);

	DECLARE @BOPHAN NVARCHAR(200), @PHANLOAI NVARCHAR(50);
	DECLARE @COL1 FLOAT, @COL2 FLOAT, @COL3 FLOAT, @COL4 FLOAT, @COL5 FLOAT, @COL6 FLOAT, @COL7 FLOAT;

	DECLARE CUR CURSOR LOCAL FOR
		SELECT A.bophan, 
			CASE 
				WHEN A.phanloai = 'METKHOI' THEN N'Mét khối' 
				WHEN A.phanloai = 'METVUONG' THEN N'Mét vuông' 
				ELSE A.phanloai
			END AS phanloai,
			col1 = COALESCE(col1, 0), 
			col2 = COALESCE(col2, 0), 
			col3 = COALESCE(col3, 0), 
			col4 = COALESCE(col4, 0), 
			col5 = COALESCE(col5, 0), 
			col6 = COALESCE(col6, 0), 
			col7 = COALESCE(col7, 0)
		FROM #THONGKE_SANPHAM A
		ORDER BY bophan, phanloai
	OPEN CUR
	FETCH NEXT FROM CUR INTO @BOPHAN, @PHANLOAI, @COL1, @COL2, @COL3, @COL4, @COL5, @COL6, @COL7;
	WHILE @@FETCH_STATUS = 0
	BEGIN
		DECLARE @row nvarchar(max) = '';
		SET @row = N'<tr>'
		SET @row = @row + char(10) + N'<td style=''width: 200px; VERTICAL-ALIGN: middle; TEXT-ALIGN: left;''>' + @BOPHAN + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: left;''>' + @PHANLOAI + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@COL1 = 0, '&nbsp;', FORMAT(@COL1, '#,0.###')) + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@COL2 = 0, '&nbsp;', FORMAT(@COL2, '#,0.###')) + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@COL3 = 0, '&nbsp;', FORMAT(@COL3, '#,0.###')) + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@COL4 = 0, '&nbsp;', FORMAT(@COL4, '#,0.###')) + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@COL5 = 0, '&nbsp;', FORMAT(@COL5, '#,0.###')) + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@COL6 = 0, '&nbsp;', FORMAT(@COL6, '#,0.###')) + '</td>'
		SET @row = @row + char(10) + N'<td style=''width: 80px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@COL7 = 0, '&nbsp;', FORMAT(@COL7, '#,0.###')) + '</td>'
		SET @row = @row + char(10) + N'</tr>'

		INSERT @HtmlRow1(htmlString) VALUES (@row);

		FETCH NEXT FROM CUR INTO @BOPHAN, @PHANLOAI, @COL1, @COL2, @COL3, @COL4, @COL5, @COL6, @COL7;
	END
	CLOSE CUR;
	DEALLOCATE CUR;

	INSERT @HtmlRow1(htmlString) VALUES (N'</table>');
	SELECT stt,htmlString FROM @HtmlRow1 ORDER BY stt;

